blocks.css:
.mr-header-demo{position:relative;height:240px;border-radius:14px;overflow:hidden;background:#000;font-family:'Pretendard',sans-serif}
.mr-header-bg{position:absolute;inset:0;background:linear-gradient(135deg,#1a1a1a 0%,#2a2a2a 60%,#dd0031 130%);display:flex;align-items:center;justify-content:center;overflow:hidden}
.mr-hero-watermark{font-family:'Outfit','Pretendard',sans-serif;font-weight:800;font-size:80px;color:rgba(255,255,255,.06);letter-spacing:-.02em;white-space:nowrap}
.mr-h{position:absolute;top:0;left:0;width:100%;height:80px;z-index:999;background:transparent;display:flex;align-items:center;padding:0 60px}
.mr-h-inner{display:flex;align-items:center;justify-content:space-between;width:100%}
.mr-logo a{display:inline-block}
.mr-logo img{display:block;height:39px;width:auto;filter:brightness(0) invert(1)}
.mr-gnb ul{display:flex;gap:46px;list-style:none;margin:0;padding:0}
.mr-gnb a{font-family:'Outfit','Pretendard',sans-serif;color:#fff;text-decoration:none;font-size:17px;font-weight:500;letter-spacing:.01em;transition:color .4s ease-in-out}
.mr-gnb a:hover{color:#dd0031}
.mr-util{display:flex;align-items:center;gap:22px}
.mr-lang{display:flex;gap:8px;list-style:none;margin:0;padding:0;font-family:'Outfit',monospace;font-size:14px}
.mr-lang a{color:rgba(255,255,255,.6);text-decoration:none;padding:4px 6px;letter-spacing:.04em}
.mr-lang li.cur a{color:#fff;font-weight:600}
.mr-member{color:#fff;display:flex;align-items:center;justify-content:center;width:32px;height:32px}
.mr-open{width:34px;height:34px;background:transparent;border:0;position:relative;cursor:pointer;padding:0}
.mr-open .line{position:absolute;left:6px;width:22px;height:2px;background:#fff;transition:all .4s ease-in-out}
.mr-open .line1{top:12px}
.mr-open .line2{top:20px;width:14px;right:6px;left:auto}

.mr-hero{position:relative;width:100%;height:560px;background:#000;overflow:hidden;border-radius:14px;font-family:'Outfit','Pretendard',sans-serif}
.mr-hero-grid{position:absolute;inset:0;display:grid;grid-template-columns:repeat(5,1fr);gap:6px;padding:6px;filter:grayscale(.6) brightness(.5) contrast(1.05)}
.mr-col{overflow:hidden;border-radius:4px;position:relative}
.mr-col ul{list-style:none;margin:0;padding:0;display:flex;flex-direction:column;gap:6px;animation-duration:28s;animation-timing-function:linear;animation-iteration-count:infinite}
.mr-col-up ul{animation-name:mr-col-up}
.mr-col-down ul{animation-name:mr-col-down}
.mr-col li{flex-shrink:0;height:280px;border-radius:3px;overflow:hidden}
.mr-col img{width:100%;height:100%;object-fit:cover;display:block}
.mr-col:nth-child(1) ul{animation-duration:26s}
.mr-col:nth-child(2) ul{animation-duration:32s}
.mr-col:nth-child(3) ul{animation-duration:24s}
.mr-col:nth-child(4) ul{animation-duration:30s}
.mr-col:nth-child(5) ul{animation-duration:28s}
@keyframes mr-col-up{0%{transform:translateY(0)}100%{transform:translateY(-50%)}}
@keyframes mr-col-down{0%{transform:translateY(-50%)}100%{transform:translateY(0)}}
.mr-hero-overlay{position:absolute;inset:0;background:radial-gradient(circle at center,rgba(0,0,0,.35) 0%,rgba(0,0,0,.55) 100%);z-index:1}
.mr-hero-text{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:2;text-align:center;pointer-events:none}
.mr-hero-h2{font-family:'Outfit',sans-serif;font-weight:600;font-size:96px;line-height:1.05;letter-spacing:-.02em;margin:0;color:#dd0031;opacity:0;animation:mr-text-active 1.5s cubic-bezier(.4,0,.2,1) .3s forwards}
.mr-hero-p{font-family:'Outfit',sans-serif;font-weight:500;font-size:22px;color:#fff;margin:16px 0 0;letter-spacing:.04em;opacity:0;animation:mr-text-active 1.5s cubic-bezier(.4,0,.2,1) .8s forwards}
@keyframes mr-text-active{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}
.mr-hero-scroll{position:absolute;bottom:24px;left:60px;font-family:'Outfit',sans-serif;font-size:12px;letter-spacing:.2em;color:rgba(255,255,255,.8);display:flex;align-items:center;gap:12px;z-index:3}
.mr-hero-scroll .dots{display:flex;gap:4px}
.mr-hero-scroll .dots i{display:block;width:4px;height:4px;border-radius:50%;background:#fff;opacity:.3;animation:mr-dotfade 1.5s ease infinite}
.mr-hero-scroll .dots .d2{animation-delay:.3s}
.mr-hero-scroll .dots .d3{animation-delay:.6s}
@keyframes mr-dotfade{0%,100%{opacity:.3}50%{opacity:1}}

.mr-about{position:relative;width:100%;background:linear-gradient(180deg,#fff 0%,#fde7e5 65%,#fbd6d2 100%);padding:80px 0 60px;overflow:hidden;border-radius:14px;font-family:'Pretendard',sans-serif;display:flex;flex-direction:column;gap:40px}
.mr-marquee{width:100%;height:120px;overflow:hidden;display:flex;align-items:center}
.mr-mar-ch{font-family:'Outfit',sans-serif;font-weight:800;font-size:120px;color:rgba(0,0,0,.07);white-space:nowrap;line-height:1;letter-spacing:-.02em;animation:mr-marquee 20s linear infinite}
@keyframes mr-marquee{from{transform:translateX(0)}to{transform:translateX(-76.748%)}}
.mr-about-top{max-width:1400px;margin:0 auto;padding:0 60px;width:100%}
.mr-about-h4{font-family:'Pretendard',sans-serif;font-weight:800;font-size:42px;line-height:1.35;color:#000;margin:0;letter-spacing:-.02em}
.mr-about-h4 span{display:inline-block}
.mr-about-h4 .red{color:#dd0031}
.mr-about-bottom{position:relative;display:grid;grid-template-columns:1.1fr 1fr;gap:40px;max-width:1400px;margin:0 auto;padding:60px 60px 0;align-items:center}
.mr-about-bg-txt{position:absolute;top:50%;left:50%;transform:translate(-50%,-30%);font-family:'Outfit',sans-serif;font-weight:800;font-size:240px;color:rgba(221,0,49,.05);letter-spacing:-.04em;white-space:nowrap;pointer-events:none;z-index:0;line-height:1}
.mr-about-cell{width:100%;max-width:600px;height:auto;display:block;justify-self:start;position:relative;z-index:1;filter:drop-shadow(0 30px 60px rgba(221,0,49,.18))}
.mr-about-counter{display:flex;flex-direction:column;gap:0;position:relative;z-index:1}
.mr-stat{display:flex;justify-content:space-between;align-items:flex-end;gap:30px;padding:30px 0;border-bottom:1px solid rgba(0,0,0,.1)}
.mr-stat:first-child{padding-top:0}
.mr-stat:last-child{border-bottom:0;padding-bottom:0}
.mr-stat-left{display:flex;flex-direction:column;gap:6px}
.mr-stat dt{font-family:'Pretendard',sans-serif;font-weight:700;font-size:22px;color:#000;margin:0;letter-spacing:-.01em}
.mr-stat p{font-family:'Pretendard',sans-serif;font-size:14px;color:#444;margin:0}
.mr-stat strong{font-family:'Outfit',sans-serif;font-weight:700;font-size:84px;color:#000;line-height:.95;letter-spacing:-.03em;flex-shrink:0}

.mr-product{padding:80px 0 80px;background:#fff;border-radius:14px;font-family:'Pretendard',sans-serif;overflow:hidden}
.mr-product-head{display:flex;flex-direction:column;gap:20px;margin:0 60px 60px;max-width:900px}
.mr-product-head .mr-tag{font-family:'Outfit',sans-serif;font-size:14px;font-weight:600;color:#dd0031;letter-spacing:.25em}
.mr-product-h4{font-family:'Pretendard',sans-serif;font-weight:800;font-size:46px;line-height:1.35;color:#000;margin:0;letter-spacing:-.02em}
.mr-product-h4 .red{color:#dd0031}
.mr-product-track{overflow:hidden;padding:10px 0 30px}
.mr-product-list{display:flex;gap:24px;list-style:none;margin:0;padding:0 60px;animation:mr-product-scroll 30s linear infinite;width:max-content}
@keyframes mr-product-scroll{from{transform:translateX(0)}to{transform:translateX(calc(-50% - 12px))}}
.mr-prd-card{flex:0 0 auto;width:340px;height:430px;border-radius:14px;background:#fff;overflow:hidden;box-shadow:0 4px 16px rgba(0,0,0,.04);transition:transform .4s ease-in-out,box-shadow .4s ease-in-out;border:1px solid #ebebeb}
.mr-prd-card:hover{transform:translateY(-8px);box-shadow:0 18px 40px rgba(0,0,0,.08);border-color:#dd0031}
.mr-prd-card a{display:flex;flex-direction:column;height:100%;padding:30px;text-decoration:none;color:#000}
.mr-prd-card .img-wrap{flex:1;background:#f5f5f5;border-radius:8px;display:flex;align-items:center;justify-content:center;overflow:hidden;padding:24px}
.mr-prd-card img{width:100%;height:100%;object-fit:contain;display:block}
.mr-prd-card span{display:block;margin-top:22px;font-family:'Outfit','Pretendard',sans-serif;font-weight:600;font-size:22px;letter-spacing:-.01em;text-align:center;color:#000}

.mr-news{padding:80px 60px;background:#fff;border-radius:14px;font-family:'Pretendard',sans-serif;max-width:1400px;margin:0 auto}
.mr-news-head{display:flex;justify-content:space-between;align-items:flex-end;gap:30px;margin-bottom:50px;border-bottom:1px solid #ebebeb;padding-bottom:30px}
.mr-news-head .mr-tag{display:block;font-family:'Outfit',sans-serif;font-size:14px;font-weight:600;color:#dd0031;letter-spacing:.2em;margin-bottom:18px}
.mr-news-h4{font-family:'Pretendard',sans-serif;font-weight:800;font-size:38px;line-height:1.35;color:#000;margin:0;letter-spacing:-.02em}
.mr-news-more{display:inline-flex;align-items:center;gap:10px;font-family:'Outfit',sans-serif;font-weight:600;font-size:14px;color:#000;text-decoration:none;letter-spacing:.05em;padding:14px 24px;border:1px solid #000;border-radius:99px;transition:background .4s,color .4s}
.mr-news-more i{width:14px;height:1px;background:currentColor;display:inline-block;position:relative}
.mr-news-more i::after{content:'';position:absolute;right:0;top:-3px;width:7px;height:7px;border-top:1px solid currentColor;border-right:1px solid currentColor;transform:rotate(45deg)}
.mr-news-more:hover{background:#000;color:#fff}
.mr-news-list{list-style:none;margin:0;padding:0;display:flex;flex-direction:column}
.mr-news-list li{border-bottom:1px solid #ebebeb;transition:background .3s}
.mr-news-list li:hover{background:#fafafa}
.mr-news-list a{display:grid;grid-template-columns:140px 1fr 40px;align-items:center;gap:30px;padding:24px 16px;color:#000;text-decoration:none;font-size:17px}
.mr-news-list .date{font-family:'Outfit',sans-serif;font-weight:500;color:#666;font-size:14px;letter-spacing:.04em}
.mr-news-list strong{font-family:'Pretendard',sans-serif;font-weight:500;color:#111;font-size:18px;letter-spacing:-.01em;display:block}
.mr-news-list .arrow{justify-self:end;font-size:20px;color:#999;transition:color .3s,transform .3s}
.mr-news-list li:hover .arrow{color:#dd0031;transform:translateX(4px)}

.mr-contact{position:relative;background:#000 url('https://miracell.co.kr/images/main/main_contact_bg.jpg') right center/cover no-repeat;padding:90px 60px;border-radius:14px;display:grid;grid-template-columns:1fr auto;gap:40px;align-items:center;font-family:'Pretendard',sans-serif;min-height:450px;overflow:hidden}
.mr-contact-network{position:absolute;inset:0;background:radial-gradient(ellipse at 70% 50%,rgba(221,0,49,.5) 0%,rgba(221,0,49,.1) 30%,transparent 65%);mix-blend-mode:screen;pointer-events:none}
.mr-contact > *:not(.mr-contact-network){position:relative;z-index:1}
.mr-contact-text{color:#fff}
.mr-contact-h4{font-family:'Outfit',sans-serif;font-weight:700;font-size:80px;color:#fff;margin:0 0 30px;letter-spacing:-.02em;line-height:1.1}
.mr-contact-p{font-family:'Pretendard',sans-serif;font-size:17px;line-height:1.7;color:rgba(255,255,255,.85);margin:0;max-width:540px}
.mr-contact-arrow-wrap{position:relative;display:flex;align-items:center;gap:0;padding-right:20px;z-index:2}
.mr-contact-line{width:280px;height:1px;background:#fff;position:relative;margin-right:-1px}
.mr-contact-line::after{content:'';position:absolute;right:-2px;top:-4px;width:0;height:0;border-left:8px solid #fff;border-top:4px solid transparent;border-bottom:4px solid transparent}
.mr-contact-btn{position:relative;width:160px;height:160px;display:flex;align-items:center;justify-content:center;border-radius:50%;border:1px solid rgba(255,255,255,.4);text-decoration:none;flex-shrink:0;transition:transform .4s}
.mr-contact-btn:hover{transform:scale(1.05)}
.mr-spin-text{position:absolute;inset:0;animation:mr-spin 14s linear infinite}
.mr-arrow-icon{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);color:#fff}
@keyframes mr-spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}

.mr-footer{background:#fff;color:#666;font-family:'Pretendard',sans-serif;border-radius:14px;overflow:hidden;border:1px solid #ebebeb}
.mr-footer-top{padding:60px;border-bottom:1px solid #ebebeb}
.mr-footer-top-inner{display:grid;grid-template-columns:1.4fr 1fr;gap:60px;max-width:1400px;margin:0 auto}
.mr-footer-left{display:flex;flex-direction:column;gap:24px}
.mr-foot-logo img{height:36px;width:auto;display:block;filter:grayscale(1) opacity(.7)}
.mr-footer-addr strong{display:block;font-family:'Outfit',sans-serif;font-weight:600;font-size:16px;color:#111;margin-bottom:12px;letter-spacing:.04em}
.mr-footer-addr p{font-size:13px;color:#666;line-height:1.8;margin:0;letter-spacing:-.01em}
.mr-footer-addr p a{color:#666;text-decoration:none}
.mr-footer-right{display:flex;flex-direction:column;gap:20px}
.mr-footer-nav{list-style:none;margin:0;padding:0;display:grid;grid-template-columns:repeat(3,1fr);gap:12px}
.mr-footer-nav a{font-family:'Outfit',sans-serif;font-weight:500;font-size:14px;color:#111;text-decoration:none;letter-spacing:.02em;transition:color .3s}
.mr-footer-nav a:hover{color:#dd0031}
.mr-family button{font-family:'Outfit',sans-serif;font-size:13px;font-weight:500;color:#111;background:transparent;border:1px solid #ddd;border-radius:99px;padding:10px 18px;display:inline-flex;align-items:center;gap:10px;cursor:pointer}
.mr-family button span{color:#dd0031;font-weight:600}
.mr-footer-policy{list-style:none;margin:0;padding:0;display:flex;gap:14px}
.mr-footer-policy a{font-family:'Outfit',sans-serif;font-size:13px;color:#111;text-decoration:none;font-weight:600;display:inline-flex;align-items:center;gap:6px}
.mr-footer-policy a span{color:#dd0031;font-size:14px}
.mr-footer-bottom{padding:24px 60px;background:#fafafa}
.mr-footer-bottom-inner{display:flex;justify-content:space-between;align-items:center;gap:30px;max-width:1400px;margin:0 auto}
.mr-sns{list-style:none;margin:0;padding:0;display:flex;gap:10px}
.mr-sns a{width:36px;height:36px;border:1px solid #ddd;border-radius:50%;display:flex;align-items:center;justify-content:center;color:#111;transition:all .3s}
.mr-sns a:hover{background:#111;color:#fff;border-color:#111}
.mr-copy{font-family:'Outfit',sans-serif;font-size:12px;color:#999;margin:0;letter-spacing:.04em}

.mr-splitdemo{padding:48px;background:#f5f5f5;border-radius:12px;font-family:'Pretendard',sans-serif}
.mr-splitdemo h4{font-family:'Pretendard',sans-serif;font-weight:800;font-size:32px;line-height:1.4;color:#000;margin:0;letter-spacing:-.02em}
.mr-splitdemo h4 span{display:inline-block;opacity:0;transform:translateY(40px);animation:mr-text-active 1.5s cubic-bezier(.4,0,.2,1) forwards}
.mr-splitdemo h4 span:nth-child(1){animation-delay:.1s}
.mr-splitdemo h4 span:nth-child(2){animation-delay:.15s}
.mr-splitdemo h4 span:nth-child(3){animation-delay:.2s}
.mr-splitdemo h4 span:nth-child(4){animation-delay:.25s}
.mr-splitdemo h4 span:nth-child(5){animation-delay:.3s}
.mr-splitdemo h4 span:nth-child(6){animation-delay:.35s}
.mr-splitdemo h4 span:nth-child(7){animation-delay:.4s}
.mr-splitdemo h4 span:nth-child(8){animation-delay:.45s}
.mr-splitdemo h4 span:nth-child(9){animation-delay:.5s}
.mr-splitdemo h4 span:nth-child(10){animation-delay:.55s}
.mr-splitdemo h4 span:nth-child(11){animation-delay:.6s}
@keyframes mr-text-active{from{opacity:0;transform:translateY(40px)}to{opacity:1;transform:translateY(0)}}
.mr-splitdemo small{display:block;margin-top:24px;font-family:'Outfit',monospace;font-size:12px;color:#dd0031;letter-spacing:.02em}

.mr-pointer-demo{padding:60px;background:#fafafa;border-radius:14px;display:grid;grid-template-columns:240px 1fr;gap:60px;align-items:center;font-family:'Pretendard',sans-serif}
.mr-pointer-stage{position:relative;width:240px;height:240px;display:flex;align-items:center;justify-content:center}
.mr-pointer-bg{position:absolute;width:191px;height:191px;animation:mr-pointer-bg-anim 14s linear infinite}
.mr-pointer-bg img{width:100%;height:100%;display:block;animation:mr-spin 14s linear infinite}
.mr-pointer-txt{position:absolute;width:163px;height:163px}
.mr-pointer-txt img{width:100%;height:100%;display:block;animation:mr-spin 14s linear infinite reverse}
.mr-pointer-plus{position:absolute;width:30px;height:30px;color:#fff;font-size:30px;font-weight:300;line-height:1;display:flex;align-items:center;justify-content:center}
@keyframes mr-spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}
@keyframes mr-pointer-bg-anim{0%,100%{transform:scale(1)}50%{transform:scale(1.04)}}
.mr-pointer-meta{font-family:'Pretendard',sans-serif;font-size:14px;color:#333;line-height:1.9;display:flex;flex-direction:column;gap:6px}
.mr-pointer-meta b{font-family:'Outfit',monospace;color:#dd0031;font-size:12px;font-weight:600;margin-right:8px;letter-spacing:.02em}
